step.example:

@Entity
@Table(name = "users")
public class User {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(nullable = false, unique = true)
    private String username;

    @Column(nullable = false)
    private String password; // BCrypt hashed

    @OneToMany(mappedBy = "user", cascade = CascadeType.ALL)
    private List<Account> accounts;
}

step.pattern:

public interface UserRepository extends JpaRepository<User, Long> {
    Optional<User> findByUsername(String username);
    boolean existsByUsername(String username);
}

public interface AccountRepository extends JpaRepository<Account, Long> {
    List<Account> findByUserId(Long userId);
    Optional<Account> findByAccountNumber(String accountNumber);
}

public interface TransactionRepository extends JpaRepository<Transaction, Long> {
    List<Transaction> findByAccountIdOrderByTimestampDesc(Long accountId);
    List<Transaction> findByAccountIdAndTimestampBetween(
        Long accountId, LocalDateTime start, LocalDateTime end
    );
}

step.example:

@Service
@Transactional
@Slf4j
public class TransferService {

    private final AccountRepository accountRepository;
    private final TransactionRepository transactionRepository;

    public TransferResponse executeTransfer(TransferRequest request) {
        log.info("Executing transfer from {} to {}", 
            request.getFromAccount(), request.getToAccount());

        Account fromAccount = accountRepository
            .findByAccountNumber(request.getFromAccount())
            .orElseThrow(() -> new AccountNotFoundException("Source account not found"));

        Account toAccount = accountRepository
            .findByAccountNumber(request.getToAccount())
            .orElseThrow(() -> new AccountNotFoundException("Destination account not found"));

        if (fromAccount.getBalance().compareTo(request.getAmount()) < 0) {
            throw new InsufficientFundsException("Insufficient balance");
        }

        fromAccount.setBalance(fromAccount.getBalance().subtract(request.getAmount()));
        toAccount.setBalance(toAccount.getBalance().add(request.getAmount()));

        Transaction debitTxn = createTransaction(fromAccount, request.getAmount().negate(), "DEBIT");
        Transaction creditTxn = createTransaction(toAccount, request.getAmount(), "CREDIT");

        accountRepository.saveAll(List.of(fromAccount, toAccount));
        transactionRepository.saveAll(List.of(debitTxn, creditTxn));

        return new TransferResponse(true, "Transfer successful");
    }
}

step.rest_controller_example:

@RestController
@RequestMapping("/api/accounts")
@Slf4j
public class AccountController {

    private final AccountService accountService;

    @GetMapping
    public ResponseEntity<List<AccountDTO>> getUserAccounts(Principal principal) {
        log.info("Fetching accounts for user: {}", principal.getName());
        List<AccountDTO> accounts = accountService.getAccountsByUsername(principal.getName());
        return ResponseEntity.ok(accounts);
    }

    @GetMapping("/{id}")
    public ResponseEntity<AccountDTO> getAccount(@PathVariable Long id, Principal principal) {
        AccountDTO account = accountService.getAccount(id, principal.getName());
        return ResponseEntity.ok(account);
    }
}

step.mvc_controller_example:

@Controller
@RequestMapping("/accounts")
@Slf4j
public class AccountController {

    private final AccountService accountService;

    @GetMapping
    public String listAccounts(Model model, Principal principal) {
        log.info("Displaying accounts for user: {}", principal.getName());
        List<AccountDTO> accounts = accountService.getAccountsByUsername(principal.getName());
        model.addAttribute("accounts", accounts);
        return "accounts/list";
    }
}

step.example:

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/", "/login", "/css/**", "/js/**").permitAll()
                .requestMatchers("/actuator/health", "/actuator/info").permitAll()
                .anyRequest().authenticated()
            )
            .formLogin(form -> form
                .loginPage("/login")
                .defaultSuccessUrl("/accounts", true)
                .permitAll()
            )
            .logout(logout -> logout
                .logoutSuccessUrl("/login?logout")
                .permitAll()
            );
        return http.build();
    }

    @Bean
    public PasswordEncoder passwordEncoder() {
        return new BCryptPasswordEncoder();
    }
}

